// @vitest-environment node
/**
 * SPEC-046: Nota de resumen con N participantes — el user prompt de la nota
 * recibe el mismo tratamiento que el del guión: línea «Contexto:» de la
 * empresa y sección «## Contactos» con un bloque por participante (en el
 * orden de contactIds); las degradaciones de SPEC-020 se conservan EXACTAS y
 * la nota NO incluye objetivos de discovery/grupo (decisión asumida de la
 * spec). El system prompt NO cambia.
 * Generated by QA Dev agent.
 *
 * Mismo arnés que noteService.test.ts (SPEC-017): SDK mockeado, dialog
 * mockeado y store/repository REALES con transcript.json real en temporal.
 */
import { mkdtempSync, writeFileSync } from 'fs'
import { tmpdir } from 'os'
import { join } from 'path'
import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest'
import * as repository from '../../../src/main/db/repository'
import { initStore } from '../../../src/main/db/store'
import { generateInterviewNote } from '../../../src/main/noteService'
import type { NoteTemplate } from '../../../src/renderer/src/types/domain'

const harness = vi.hoisted(() => {
  /** Jerarquía espejo de la del SDK: instanceof debe funcionar en mapSdkError. */
  class APIError extends Error {}
  class AuthenticationError extends APIError {}
  class RateLimitError extends APIError {}
  class APIConnectionError extends APIError {}
  return {
    create: vi.fn(),
    showSaveDialog: vi.fn(),
    errors: { APIError, AuthenticationError, RateLimitError, APIConnectionError }
  }
})

vi.mock('@anthropic-ai/sdk', () => {
  class MockAnthropic {
    static APIError = harness.errors.APIError
    static AuthenticationError = harness.errors.AuthenticationError
    static RateLimitError = harness.errors.RateLimitError
    static APIConnectionError = harness.errors.APIConnectionError
    readonly messages = { create: harness.create }
  }
  return { default: MockAnthropic }
})

vi.mock('electron', () => ({
  app: {
    getPath: (): string => {
      throw new Error('app.getPath no debe usarse en tests: initStore recibe baseDir inyectado')
    }
  },
  dialog: {
    showSaveDialog: harness.showSaveDialog
  },
  safeStorage: {
    isEncryptionAvailable: (): boolean => true,
    encryptString: (plain: string): Buffer => Buffer.from(plain, 'utf8'),
    decryptString: (blob: Buffer): string => blob.toString('utf8')
  }
}))

/** Respuesta del SDK con bloque thinking + bloque text (el JSON va en text). */
function sdkResponse(payload: Record<string, unknown>): unknown {
  return {
    stop_reason: 'end_turn',
    content: [
      { type: 'thinking', thinking: 'razonamiento' },
      { type: 'text', text: JSON.stringify(payload) }
    ]
  }
}

const GENERATED = {
  sections: [{ title: 'da igual', contentMarkdown: 'Registro manual detectado.' }]
}

function writeTranscriptFile(): string {
  const dir = mkdtempSync(join(tmpdir(), 'maurya-participants-transcript-'))
  const transcriptPath = join(dir, 'entrevista.transcript.json')
  writeFileSync(
    transcriptPath,
    JSON.stringify({
      lines: [
        {
          channel: 'mic',
          speaker: 0,
          text: '¿Cómo gestionáis hoy el registro?',
          startMs: 0,
          endMs: 1000,
          receivedAtMs: 1100
        }
      ],
      latency: null,
      assistant: null
    })
  )
  return transcriptPath
}

/** Note-template mínimo de una sección. */
function seedNoteTemplate(): NoteTemplate {
  return repository.createNoteTemplate({
    name: 'Notas discovery',
    sections: [{ title: 'Dolores', description: 'Problemas detectados' }]
  })
}

function sentUserPrompt(): string {
  const params = harness.create.mock.calls[0][0] as {
    messages: Array<{ content: string }>
  }
  return params.messages[0].content
}

let dataDir = ''

beforeEach(() => {
  vi.clearAllMocks()
  dataDir = mkdtempSync(join(tmpdir(), 'maurya-notes-participants-'))
  initStore(dataDir)
  process.env['ANTHROPIC_API_KEY'] = 'sk-ant-test'
})

afterEach(() => {
  delete process.env['ANTHROPIC_API_KEY']
})

describe('noteService (SPEC-046 participantes)', () => {
  // SPEC-046 · AC-20: bloque por participante con contexto (mismo tratamiento
  // que el guión) + línea Contexto de la empresa, en el orden de contactIds
  it('includes the company context and one block per participant with name, cargo, LinkedIn and contexto in contactIds order', async () => {
    const discovery = repository.createDiscovery({ name: 'Vertical Sanidad' })
    const company = repository.createCompany({
      name: 'Acme Corp',
      website: 'https://acme.example',
      context: 'Scale-up MedTech con certificación MDR en curso'
    })
    const jane = repository.createContact({
      companyId: company.id,
      name: 'Jane Doe',
      position: 'CTO',
      linkedinUrl: 'https://linkedin.com/in/janedoe',
      context: 'Impulsa la digitalización del área regulatoria'
    })
    const john = repository.createContact({
      companyId: company.id,
      name: 'John Smith',
      context: 'Escéptico con herramientas nuevas'
    })
    const template = seedNoteTemplate()
    const interview = repository.createInterview({
      discoveryId: discovery.id,
      companyId: company.id,
      // Orden de marcado inverso al de alta: manda el orden de contactIds
      contactIds: [john.id, jane.id],
      title: 'Discovery con Acme'
    })
    repository.updateInterview(interview.id, {
      transcriptPath: writeTranscriptFile(),
      status: 'recorded'
    })
    harness.create.mockResolvedValue(sdkResponse(GENERATED))

    const result = await generateInterviewNote(interview.id, template.id)

    const userPrompt = sentUserPrompt()
    expect(userPrompt).toContain(
      '## Empresa\nNombre: Acme Corp\nWeb: https://acme.example\n' +
        'Contexto: Scale-up MedTech con certificación MDR en curso'
    )
    expect(userPrompt).toContain(
      '## Contactos\n' +
        'Nombre: John Smith\nContexto: Escéptico con herramientas nuevas\n\n' +
        'Nombre: Jane Doe\nCargo: CTO\nLinkedIn: https://linkedin.com/in/janedoe\n' +
        'Contexto: Impulsa la digitalización del área regulatoria'
    )
    expect(result.interview.status).toBe('summarized')
  })

  // SPEC-046 · AC-20 (degradación intacta): con empresa pero sin contactos la
  // sección conserva el texto EXACTO de SPEC-020, y la nota se genera igual
  it('keeps the exact "Sin contacto asignado." degradation when the interview has a company but no contacts', async () => {
    const discovery = repository.createDiscovery({ name: 'Vertical Sanidad' })
    const company = repository.createCompany({ name: 'Acme Corp' })
    const template = seedNoteTemplate()
    const interview = repository.createInterview({
      discoveryId: discovery.id,
      companyId: company.id,
      title: 'Discovery con Acme'
    })
    repository.updateInterview(interview.id, {
      transcriptPath: writeTranscriptFile(),
      status: 'recorded'
    })
    harness.create.mockResolvedValue(sdkResponse(GENERATED))

    const result = await generateInterviewNote(interview.id, template.id)

    expect(sentUserPrompt()).toContain('## Contactos\nSin contacto asignado.')
    expect(result.note.contentMarkdown).toBe('## Dolores\n\nRegistro manual detectado.')
  })

  // SPEC-046 · AC-20 (decisión asumida: la nota NO incluye objetivos de
  // discovery/grupo — solo participantes; el alcance de objetivos es del guión)
  it('does not include the discovery objectives nor the group objective sections in the note prompt', async () => {
    const discovery = repository.createDiscovery({
      name: 'Vertical Sanidad',
      objectives: 'Entender el problema real'
    })
    const group = repository.createInterviewGroup({
      discoveryId: discovery.id,
      name: 'Founders',
      objective: 'Detectar dolores'
    })
    const company = repository.createCompany({ name: 'Acme Corp' })
    const template = seedNoteTemplate()
    const interview = repository.createInterview({
      discoveryId: discovery.id,
      interviewGroupId: group.id,
      companyId: company.id,
      title: 'Discovery con Acme'
    })
    repository.updateInterview(interview.id, {
      transcriptPath: writeTranscriptFile(),
      status: 'recorded'
    })
    harness.create.mockResolvedValue(sdkResponse(GENERATED))

    await generateInterviewNote(interview.id, template.id)

    const userPrompt = sentUserPrompt()
    expect(userPrompt).not.toContain('## Objetivos del discovery')
    expect(userPrompt).not.toContain('## Objetivo del grupo')
  })
})
